// Simple Icons CDN: https://cdn.simpleicons.org/{slug}/{hex}
// Google Favicon: https://t2.gstatic.com/faviconV2?...
const SI = (slug, hex) => `https://cdn.simpleicons.org/${slug}/${hex}`;
const GF = (domain) => `https://t2.gstatic.com/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=https://${domain}&size=256`;

function logoFail(img, fallback, color, initials) {
  if (img._tried) {
    img.onerror = null;
    const fs = initials.length > 4 ? 14 : initials.length > 3 ? 16 : 20;
    img.src = 'data:image/svg+xml,' + encodeURIComponent(
      `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 120 80"><rect width="120" height="80" rx="8" fill="#${color}"/><text x="60" y="46" font-family="Arial Black,sans-serif" font-weight="900" font-size="${fs}" fill="white" text-anchor="middle" dominant-baseline="middle">${initials}</text></svg>`
    );
  } else {
    img._tried = true;
    img.src = fallback;
  }
}

const BRANDS = [
  // TECH
  { id:1,  name:'Apple',          logo:SI('apple','FFFFFF'),           fallback:GF('apple.com'),           color:'FFFFFF', initials:'AAPL', sector:'Technology',   founded:'Cupertino, California, USA', year:1976, story:'Apple Inc. was founded on April 1, 1976 by Steve Jobs, Steve Wozniak, and Ronald Wayne in a garage in Los Altos, California. The company started by selling hand-built personal computers before revolutionising the world with the Macintosh in 1984, the iPod in 2001, the iPhone in 2007, and the iPad in 2010. Apple became the first publicly traded US company to reach a market valuation of one trillion dollars in 2018. Its ecosystem of hardware, software, and services has made it one of the most valuable and influential companies in human history.', rating:4.9, reviews:245000 },
  { id:2,  name:'Google',         logo:SI('google','4285F4'),           fallback:GF('google.com'),          color:'4285F4', initials:'GOOG', sector:'Technology',   founded:'Menlo Park, California, USA', year:1998, story:'Google was founded in September 1998 by Larry Page and Sergey Brin while they were PhD students at Stanford University. Starting as a search engine in a garage, Google grew to become the world\'s most visited website and expanded into advertising, cloud computing, smartphones, self-driving cars, and artificial intelligence. Its parent company Alphabet was created in 2015. Google processes over 8.5 billion searches every single day and its services are used by more than four billion people worldwide.', rating:4.8, reviews:198000 },
  { id:3,  name:'Microsoft',      logo:SI('microsoft','00A4EF'),        fallback:GF('microsoft.com'),       color:'00A4EF', initials:'MSFT', sector:'Technology',   founded:'Albuquerque, New Mexico, USA', year:1975, story:'Microsoft was founded in April 1975 by Bill Gates and Paul Allen in Albuquerque, New Mexico. The company created the MS-DOS operating system that powered the IBM PC revolution, and later Windows which became the dominant desktop operating system worldwide. Microsoft Office, Azure cloud computing, Xbox gaming, and LinkedIn are among its major products today. Under CEO Satya Nadella\'s leadership since 2014, Microsoft has undergone a remarkable transformation into a cloud-first company with a market value exceeding two trillion dollars.', rating:4.7, reviews:167000 },
  { id:4,  name:'Samsung',        logo:SI('samsung','1428A0'),          fallback:GF('samsung.com'),         color:'1428A0', initials:'SAM', sector:'Technology',   founded:'Suwon, South Korea', year:1969, story:'Samsung Electronics was founded in 1969 in Suwon, South Korea, as a division of the Samsung conglomerate established by Lee Byung-chul in 1938. From humble beginnings making black-and-white televisions, Samsung grew into the world\'s largest manufacturer of smartphones, semiconductors, memory chips, and televisions. The Galaxy series of smartphones competes directly with Apple globally. Samsung accounts for roughly 20 percent of South Korea\'s total export value, making it critical to the national economy.', rating:4.6, reviews:152000 },
  { id:5,  name:'Meta',           logo:SI('meta','0866FF'),             fallback:GF('meta.com'),            color:'0866FF', initials:'META', sector:'Technology',   founded:'Cambridge, Massachusetts, USA', year:2004, story:'Meta Platforms, formerly Facebook, was founded by Mark Zuckerberg and his Harvard University roommates in February 2004. Starting as a social network for college students, it expanded to become the world\'s largest social media company with over three billion monthly active users across Facebook, Instagram, and WhatsApp. Meta has invested heavily in virtual reality through its Oculus hardware and the concept of the metaverse. Despite regulatory scrutiny and privacy controversies, Meta remains one of the most influential technology companies on earth.', rating:4.1, reviews:134000 },
  { id:6,  name:'Amazon',         logo:SI('amazon','FF9900'),           fallback:GF('amazon.com'),          color:'FF9900', initials:'AMZN', sector:'E-Commerce',   founded:'Bellevue, Washington, USA', year:1994, story:'Amazon was founded by Jeff Bezos on July 5, 1994 in his garage in Bellevue, Washington, initially as an online bookstore. Bezos chose the name Amazon because it started with the letter A and evoked the scale of the Amazon river. The company expanded into every retail category imaginable and then invented cloud computing as a business with Amazon Web Services. Today Amazon is the world\'s largest e-commerce platform, cloud provider, and one of the largest employers on earth with over 1.5 million workers.', rating:4.5, reviews:178000 },
  { id:7,  name:'Netflix',        logo:SI('netflix','E50914'),          fallback:GF('netflix.com'),         color:'E50914', initials:'NFLX', sector:'Entertainment', founded:'Scotts Valley, California, USA', year:1997, story:'Netflix was founded in August 1997 by Reed Hastings and Marc Randolph in Scotts Valley, California, originally as a DVD-by-mail rental service. In 2007 it launched its streaming service which transformed the entertainment industry. Netflix pioneered the concept of binge-watching with the release of full seasons at once and invested billions in original content including House of Cards, Stranger Things, and The Crown. It now operates in over 190 countries and has more than 260 million paying subscribers worldwide.', rating:4.5, reviews:143000 },
  { id:8,  name:'Tesla',          logo:SI('tesla','CC0000'),            fallback:GF('tesla.com'),           color:'CC0000', initials:'TSLA', sector:'Automotive',   founded:'San Carlos, California, USA', year:2003, story:'Tesla was founded in July 2003 by Martin Eberhard and Marc Tarpenning in San Carlos, California. Elon Musk joined as chairman and lead investor in 2004 and became CEO in 2008. Tesla proved that electric vehicles could be desirable, fast, and practical with the Model S, Model 3, Model X, and Model Y. It also operates the world\'s largest network of electric vehicle charging stations. Tesla\'s influence on the automotive industry has forced every major car manufacturer to accelerate their own electric vehicle programmes.', rating:4.6, reviews:121000 },
  { id:9,  name:'Spotify',        logo:SI('spotify','1DB954'),          fallback:GF('spotify.com'),         color:'1DB954', initials:'SPOT', sector:'Entertainment', founded:'Stockholm, Sweden', year:2006, story:'Spotify was founded in April 2006 by Daniel Ek and Martin Lorentzon in Stockholm, Sweden, as a response to the music piracy crisis of the early 2000s. The founders believed that legal streaming could be more convenient than piracy. Spotify launched in 2008 and transformed the music industry from album sales to streaming subscriptions. It now has over 600 million users across 180 countries and pays royalties to millions of artists. Spotify is the world\'s largest music streaming service with a catalogue of over 100 million tracks.', rating:4.7, reviews:112000 },
  { id:10, name:'Adobe',          logo:SI('adobe','FF0000'),            fallback:GF('adobe.com'),           color:'FF0000', initials:'ADBE', sector:'Technology',   founded:'Mountain View, California, USA', year:1982, story:'Adobe was founded in December 1982 by John Warnock and Charles Geschke after they left Xerox\'s Palo Alto Research Center. Adobe invented the PostScript page description language which revolutionised desktop publishing, and created PDF which became the global standard for document sharing. Creative Cloud which includes Photoshop, Illustrator, Premiere, and Acrobat is used by virtually every professional designer, filmmaker, and photographer on earth. Adobe acquired Figma in 2022 for twenty billion dollars, cementing its dominance in design tools.', rating:4.5, reviews:89000 },
  { id:11, name:'NVIDIA',         logo:SI('nvidia','76B900'),           fallback:GF('nvidia.com'),          color:'76B900', initials:'NVDA', sector:'Technology',   founded:'Santa Clara, California, USA', year:1993, story:'NVIDIA was founded in January 1993 by Jensen Huang, Chris Malachowsky, and Curtis Priem in Santa Clara, California. The company pioneered the graphics processing unit with the GeForce brand for gaming computers. Its CUDA parallel computing platform, introduced in 2006, enabled GPUs to be used for scientific computing and artificial intelligence. NVIDIA\'s chips power the majority of AI training worldwide and its market value surpassed two trillion dollars in 2024 during the AI boom. Jensen Huang is widely regarded as one of the most visionary CEOs in technology history.', rating:4.8, reviews:98000 },
  { id:12, name:'Intel',          logo:SI('intel','0071C5'),            fallback:GF('intel.com'),           color:'0071C5', initials:'INTC', sector:'Technology',   founded:'Mountain View, California, USA', year:1968, story:'Intel was founded in July 1968 by Gordon Moore and Robert Noyce after they left Fairchild Semiconductor. Moore was famous for predicting in 1965 that the number of transistors on a chip would double every two years, a principle known as Moore\'s Law. Intel\'s microprocessors powered the personal computer revolution and dominated the market for decades. The company employs over 100,000 people and has fabrication plants on multiple continents. Intel has faced increasing competition from AMD and ARM-based chips in recent years.', rating:4.3, reviews:76000 },

  // FASHION AND LUXURY
  { id:13, name:'Nike',           logo:SI('nike','111111'),             fallback:GF('nike.com'),            color:'111111', initials:'NIKE', sector:'Fashion',      founded:'Eugene, Oregon, USA', year:1964, story:'Nike was founded in January 1964 as Blue Ribbon Sports by Phil Knight and Bill Bowerman in Eugene, Oregon. Knight was a middle-distance runner under coach Bowerman at the University of Oregon. The company was renamed Nike in 1971 after the Greek goddess of victory, and the iconic Swoosh logo was designed by graphic design student Carolyn Davidson for just 35 dollars. Nike became the world\'s largest athletic footwear and apparel company through partnerships with athletes including Michael Jordan, whose Air Jordan line transformed both basketball culture and sneaker culture forever.', rating:4.7, reviews:187000 },
  { id:14, name:'Adidas',         logo:SI('adidas','000000'),           fallback:GF('adidas.com'),          color:'000000', initials:'ADS', sector:'Fashion',      founded:'Herzogenaurach, Germany', year:1949, story:'Adidas was founded in August 1949 by Adolf Dassler in Herzogenaurach, Bavaria, Germany. Adolf and his brother Rudolf had previously operated a joint shoe company before a bitter family feud split them, with Rudolf going on to found Puma. Adolf named his company Adidas by combining his nickname Adi with the first three letters of his surname. The three stripes became one of the most recognisable logos in the world. Adidas has sponsored legendary athletes and teams and is particularly dominant in football, having outfitted more World Cup winning teams than any other brand.', rating:4.6, reviews:143000 },
  { id:15, name:'Louis Vuitton',  logo:SI('louisvuitton','A8904A'),     fallback:GF('louisvuitton.com'),    color:'A8904A', initials:'LV',   sector:'Luxury',       founded:'Paris, France', year:1854, story:'Louis Vuitton was founded in 1854 by Louis Vuitton in Paris, France. Vuitton began his career as a personal box packer and luggage maker for the French aristocracy and was appointed trunk maker to Empress Eugénie, wife of Napoleon III. His flat-topped trunks which replaced the traditional dome-topped designs were revolutionary. The LV monogram canvas, introduced in 1896 by his son Georges, became one of the most counterfeited and most recognisable patterns in fashion history. Louis Vuitton is part of LVMH, the world\'s largest luxury conglomerate.', rating:4.8, reviews:98000 },
  { id:16, name:'Gucci',          logo:SI('gucci','000000'),            fallback:GF('gucci.com'),           color:'000000', initials:'GCC', sector:'Luxury',       founded:'Florence, Italy', year:1921, story:'Gucci was founded in 1921 by Guccio Gucci in Florence, Italy. Guccio had worked as a lift operator at the Savoy Hotel in London and was inspired by the luggage of wealthy guests. He opened a leather goods shop in Florence selling horse-riding equipment and luggage. The double-G logo referencing his initials became iconic. After a turbulent period of family feuds and near-bankruptcy in the 1990s, Gucci was revived by designer Tom Ford. Under Creative Director Alessandro Michele from 2015, Gucci became one of the fastest-growing luxury brands in the world.', rating:4.7, reviews:87000 },
  { id:17, name:'Chanel',         logo:SI('chanel','000000'),           fallback:GF('chanel.com'),          color:'000000', initials:'CCH', sector:'Luxury',       founded:'Paris, France', year:1910, story:'Chanel was founded in 1910 by Gabrielle "Coco" Chanel in Paris, France, initially as a hat shop in Rue Cambon. Coco Chanel revolutionised women\'s fashion by liberating women from the corset and introducing comfortable, practical clothing with a masculine influence. Chanel No. 5, launched in 1921, became the world\'s best-selling perfume of all time. The little black dress, the Chanel suit, and the quilted 2.55 handbag are permanent fixtures of fashion history. Chanel remains privately owned by the Wertheimer family and is one of the highest-valued fashion companies in the world.', rating:4.8, reviews:76000 },
  { id:18, name:'Rolex',          logo:SI('rolex','A57C3B'),            fallback:GF('rolex.com'),           color:'A57C3B', initials:'ROL', sector:'Luxury',       founded:'Geneva, Switzerland', year:1905, story:'Rolex was founded in 1905 by Hans Wilsdorf and Alfred Davis in London, England, though it later moved its operations to Geneva, Switzerland. Wilsdorf coined the name Rolex because it was easy to pronounce in any language and sounded like the noise a watch makes when being wound. In 1926 Rolex created the world\'s first waterproof wristwatch called the Oyster. Rolex watches have accompanied explorers to the top of Everest, the bottom of the ocean, and into space. The brand is privately owned by the Hans Wilsdorf Foundation and produces around one million watches per year.', rating:4.9, reviews:67000 },
  { id:19, name:'Prada',          logo:SI('prada','000000'),            fallback:GF('prada.com'),           color:'000000', initials:'PRA', sector:'Luxury',       founded:'Milan, Italy', year:1913, story:'Prada was founded in 1913 by Mario Prada in Milan, Italy, initially as a leather goods shop selling luggage, handbags, and accessories. For the first 70 years the brand remained a respected but regional Italian luxury house. Miuccia Prada, Mario\'s granddaughter, took over in 1978 and transformed Prada into a global fashion powerhouse. Her intellectually charged approach to fashion, mixing high and low culture with unexpected materials, made Prada one of the most copied and discussed brands in the world. The 2006 film The Devil Wears Prada further cemented the brand\'s cultural dominance.', rating:4.6, reviews:65000 },
  { id:20, name:'Hermès',         logo:SI('hermes','E8771A'),           fallback:GF('hermes.com'),          color:'E8771A', initials:'HMS', sector:'Luxury',       founded:'Paris, France', year:1837, story:'Hermès was founded in 1837 by Thierry Hermès in Paris, France, as a harness workshop serving European nobility. The company made saddles, bridles, and riding equipment before expanding into luggage and then fashion. The iconic Birkin bag, created in 1984 after actress Jane Birkin complained to Hermès CEO Jean-Louis Dumas that she could not find a suitable weekend bag, is now one of the most sought after luxury items on earth with waiting lists of years. Hermès remains majority family-owned and is celebrated for extraordinary craftsmanship and exclusivity.', rating:4.9, reviews:54000 },

  // BEVERAGES AND FOOD
  { id:21, name:'Coca-Cola',      logo:SI('cocacola','F40009'),         fallback:GF('coca-cola.com'),       color:'F40009', initials:'CCK', sector:'Beverages',    founded:'Atlanta, Georgia, USA', year:1886, story:'Coca-Cola was invented in May 1886 by pharmacist John Pemberton in Atlanta, Georgia, originally as a patent medicine. His bookkeeper Frank Robinson coined the name and designed the distinctive Spencerian script logo. The formula was sold to businessman Asa Candler for 2,300 dollars in 1888, who built it into a nationwide phenomenon. Coca-Cola is now sold in over 200 countries and territories, making it one of the widest-distributed products in human history. The red and white branding and contoured bottle are among the most recognisable design elements ever created.', rating:4.6, reviews:213000 },
  { id:22, name:'Pepsi',          logo:SI('pepsi','004B93'),            fallback:GF('pepsi.com'),           color:'004B93', initials:'PEP', sector:'Beverages',    founded:'New Bern, North Carolina, USA', year:1893, story:'Pepsi-Cola was created in 1893 by pharmacist Caleb Bradham in New Bern, North Carolina, who sold it from his pharmacy as a digestive aid and energy booster. The name Pepsi came from pepsin, the digestive enzyme, and kola nuts used in the original recipe. PepsiCo was formed in 1965 when Pepsi-Cola merged with Frito-Lay. The Pepsi Challenge taste tests of the 1970s and 1980s and celebrity endorsements from Michael Jackson sparked the famous Cola Wars with Coca-Cola. PepsiCo today is a diversified food and beverage giant with annual revenues exceeding 86 billion dollars.', rating:4.4, reviews:167000 },
  { id:23, name:'Starbucks',      logo:SI('starbucks','00704A'),        fallback:GF('starbucks.com'),       color:'00704A', initials:'SBUX', sector:'Beverages',   founded:'Seattle, Washington, USA', year:1971, story:'Starbucks was founded in March 1971 by Jerry Baldwin, Zev Siegl, and Gordon Bowker in Seattle, Washington, initially selling roasted coffee beans rather than prepared drinks. Howard Schultz joined in 1982 after visiting Italian espresso bars and persuaded the founders to serve espresso beverages. He eventually bought the company in 1987 and grew it into a global chain. Starbucks now operates over 36,000 locations in 84 countries, making it the largest coffeehouse chain in the world. It is credited with popularising specialty coffee culture and the concept of the third place between home and work.', rating:4.4, reviews:156000 },
  { id:24, name:'McDonald\'s',    logo:SI('mcdonalds','FBC817'),        fallback:GF('mcdonalds.com'),       color:'FBC817', initials:'MCD', sector:'Food',         founded:'San Bernardino, California, USA', year:1940, story:'McDonald\'s was founded in 1940 by Richard and Maurice McDonald in San Bernardino, California. Ray Kroc, a milkshake machine salesman, visited their restaurant in 1954 and was so impressed he bought the franchise rights in 1961. Kroc systematised and franchised the operation on a massive scale. McDonald\'s now operates over 40,000 restaurants in more than 100 countries and serves around 70 million customers every single day. The Golden Arches are said to be the second most recognisable symbol in the world after the Christian cross.', rating:4.3, reviews:198000 },
  { id:25, name:'Red Bull',       logo:SI('redbull','DB0A40'),          fallback:GF('redbull.com'),         color:'DB0A40', initials:'RB',  sector:'Beverages',    founded:'Fuschl am See, Austria', year:1984, story:'Red Bull was founded in 1984 by Austrian entrepreneur Dietrich Mateschitz and Thai businessman Chaleo Yoovidhya. Mateschitz discovered Krating Daeng, an existing Thai energy drink, during a business trip to Thailand. He partnered with Yoovidhya to adapt the formula for Western markets and created Red Bull GmbH. The slim blue and silver can launched in Austria in 1987 and went global through a revolutionary word-of-mouth marketing strategy. Red Bull now sells over 12 billion cans annually and is the world\'s leading energy drink brand, also owning Formula 1 teams and football clubs.', rating:4.5, reviews:112000 },
  { id:26, name:'Heineken',       logo:SI('heineken','007A33'),         fallback:GF('heineken.com'),        color:'007A33', initials:'HEIN', sector:'Beverages',   founded:'Amsterdam, Netherlands', year:1864, story:'Heineken was founded in 1864 by Gerard Adriaan Heineken when he purchased a brewery called De Hooiberg in Amsterdam. He hired chemist Dr. Elion, a student of Louis Pasteur, who developed the unique Heineken A-yeast still used today. The green bottle and red star became iconic worldwide. Heineken International now owns over 300 brands of beer in 190 countries and is the second-largest brewing company in the world. The brand is famous for its witty, globally consistent advertising and its sponsorship of the UEFA Champions League.', rating:4.5, reviews:98000 },
  { id:27, name:'Nestlé',         logo:SI('nestle','990000'),           fallback:GF('nestle.com'),          color:'990000', initials:'NSTLE', sector:'Food',        founded:'Vevey, Switzerland', year:1866, story:'Nestlé was founded in 1866 by Henri Nestlé in Vevey, Switzerland, initially creating infant formula for babies who could not be breastfed. The company merged with the Anglo-Swiss Condensed Milk Company in 1905 and expanded rapidly. Today Nestlé is the world\'s largest food and beverage company by revenue, with brands including Nescafé, KitKat, Milo, Maggi, Perrier, and Purina. It operates in 187 countries with 270,000 employees and annual revenues exceeding 90 billion Swiss francs.', rating:4.2, reviews:134000 },
  { id:28, name:'Heinz',          logo:SI('heinz','8C1515'),            fallback:GF('heinz.com'),           color:'8C1515', initials:'HNZ', sector:'Food',         founded:'Sharpsburg, Pennsylvania, USA', year:1869, story:'The H.J. Heinz Company was founded in 1869 by Henry John Heinz in Sharpsburg, Pennsylvania, initially selling horseradish in clear glass jars to prove purity. Heinz invented the phrase "57 Varieties" in 1896 as a marketing slogan, choosing the number for its sound even though the company already had more than 60 products at the time. Heinz Ketchup became the world\'s best-selling tomato ketchup and is found in kitchens across the globe. Kraft Heinz was formed in 2015 and is now one of the largest food companies in the world.', rating:4.3, reviews:87000 },

  // AUTOMOTIVE
  { id:29, name:'Toyota',         logo:SI('toyota','EB0A1E'),           fallback:GF('toyota.com'),          color:'EB0A1E', initials:'TYT', sector:'Automotive',   founded:'Toyota City, Japan', year:1937, story:'Toyota was founded in August 1937 by Kiichiro Toyoda in Toyota City, Aichi, Japan, as a spinoff from his father\'s textile company Toyoda Automatic Loom Works. Toyota developed the Toyota Production System, which became the foundation for lean manufacturing principles adopted worldwide. The Corolla, introduced in 1966, became the world\'s best-selling car model of all time. The Prius, launched in 1997, was the world\'s first mass-produced hybrid vehicle and pioneered the era of green motoring. Toyota is consistently the world\'s largest or second-largest car manufacturer by volume.', rating:4.7, reviews:145000 },
  { id:30, name:'BMW',            logo:SI('bmw','0066CC'),              fallback:GF('bmw.com'),             color:'0066CC', initials:'BMW', sector:'Automotive',   founded:'Munich, Germany', year:1916, story:'BMW, Bayerische Motoren Werke, was founded in March 1916 in Munich, Germany, initially as an aircraft engine manufacturer during World War I. After the war, production shifted to motorcycles and then automobiles. The blue and white roundel logo represents a spinning aircraft propeller against a blue sky. BMW became synonymous with the phrase "Ultimate Driving Machine" and built a reputation for performance, engineering precision, and luxury. The company also owns the Rolls-Royce and MINI brands. BMW is headquartered in Munich where it maintains its iconic four-cylinder tower headquarters.', rating:4.7, reviews:123000 },
  { id:31, name:'Mercedes-Benz',  logo:SI('mercedesbenz','AAAAAA'),     fallback:GF('mercedes-benz.com'),   color:'AAAAAA', initials:'MB',  sector:'Automotive',   founded:'Stuttgart, Germany', year:1926, story:'Mercedes-Benz was formed in 1926 through the merger of Karl Benz\'s Benz and Cie company with Gottlieb Daimler\'s DMG company in Stuttgart, Germany. The merger honoured the legacy of both pioneers, with Mercedes being the racing name used by Daimler\'s vehicles since 1901, named after the daughter of businessman Emil Jellinek. Benz had built the world\'s first true automobile in 1885. The three-pointed star symbolises the domination of land, sea, and air. Mercedes-Benz is the world\'s best-selling luxury automobile brand.', rating:4.8, reviews:134000 },
  { id:32, name:'Ferrari',        logo:SI('ferrari','D40000'),          fallback:GF('ferrari.com'),         color:'D40000', initials:'FERR', sector:'Automotive',  founded:'Maranello, Italy', year:1939, story:'Ferrari was founded in 1939 by Enzo Ferrari in Maranello, Italy, after he left Alfa Romeo\'s racing team. Initially the company built race cars only, with road cars produced from 1947. The prancing horse logo, the Cavallino Rampante, was given to Enzo Ferrari by the mother of World War I flying ace Francesco Baracca. Ferrari has won more Formula 1 World Championships than any other constructor. The brand is synonymous with Italian passion, performance, and exclusivity. Ferrari deliberately limits production to maintain scarcity and desirability.', rating:4.9, reviews:87000 },
  { id:33, name:'Porsche',        logo:SI('porsche','AE0000'),          fallback:GF('porsche.com'),         color:'AE0000', initials:'POR', sector:'Automotive',   founded:'Stuttgart, Germany', year:1931, story:'Porsche was founded in 1931 by Ferdinand Porsche in Stuttgart, Germany. Porsche had previously designed the Volkswagen Beetle for Adolf Hitler\'s government. His son Ferry Porsche built the first Porsche-branded car in 1948 using Volkswagen parts. The 911, introduced in 1963 with its distinctive rear-engine layout, became one of the most iconic sports cars in history and remains in continuous production today. Porsche is now owned by the Volkswagen Group and is one of the world\'s most profitable automobile manufacturers per vehicle sold.', rating:4.8, reviews:76000 },
  { id:34, name:'Ford',           logo:SI('ford','003178'),             fallback:GF('ford.com'),            color:'003178', initials:'FORD', sector:'Automotive',  founded:'Dearborn, Michigan, USA', year:1903, story:'Ford Motor Company was founded on June 16, 1903 by Henry Ford and eleven investors in Detroit, Michigan. Ford revolutionised manufacturing with the moving assembly line introduced in 1913, making the Model T affordable for ordinary Americans. "Any customer can have a car painted any colour that he wants so long as it is black" was Ford\'s famous quip. The F-Series pickup truck, first produced in 1948, has been the best-selling vehicle in the United States for over 40 consecutive years. Ford introduced the Mustang in 1964, creating the pony car segment.', rating:4.4, reviews:123000 },

  // FINANCE
  { id:35, name:'Visa',           logo:SI('visa','1A1F71'),             fallback:GF('visa.com'),            color:'1A1F71', initials:'VISA', sector:'Finance',     founded:'San Francisco, California, USA', year:1958, story:'Visa traces its origins to 1958 when Bank of America launched the BankAmericard credit card programme in Fresno, California. The programme was licensed to other banks and eventually became Visa in 1976. Visa processes over 200 billion transactions annually and is accepted at more than 80 million merchant locations in over 200 countries and territories. Visa does not issue cards or extend credit itself but provides the transaction network. It became a publicly traded company in 2008 in one of the largest IPOs in US stock market history at the time.', rating:4.6, reviews:156000 },
  { id:36, name:'Mastercard',     logo:SI('mastercard','EB001B'),       fallback:GF('mastercard.com'),      color:'EB001B', initials:'MC',  sector:'Finance',      founded:'Purchase, New York, USA', year:1966, story:'Mastercard was founded in 1966 when a group of American banks formed the Interbank Card Association as a competitor to Bank of America\'s BankAmericard. The name Mastercard was adopted in 1979. The two overlapping circles, one red and one orange, representing connectivity and partnership, are among the world\'s most recognised logos. Mastercard operates the second-largest payment network globally and processes billions of transactions daily. It became publicly traded in 2006 and has invested heavily in contactless payments and digital wallet technology.', rating:4.5, reviews:134000 },
  { id:37, name:'PayPal',         logo:SI('paypal','00457C'),           fallback:GF('paypal.com'),          color:'00457C', initials:'PYPL', sector:'Finance',     founded:'Palo Alto, California, USA', year:1998, story:'PayPal was founded in December 1998 in Palo Alto, California by a group that included Elon Musk, Peter Thiel, and Max Levchin. The company was formed from the merger of Musk\'s X.com and Thiel\'s Confinity. eBay acquired PayPal in 2002 for 1.5 billion dollars and it became the dominant payment method on the auction platform. PayPal was spun off as an independent company in 2015. It now has over 400 million active accounts worldwide and pioneered mainstream online payment security and convenience. The company also owns Venmo and other digital payment products.', rating:4.4, reviews:123000 },
  { id:38, name:'American Express',logo:SI('americanexpress','2E77BC'),  fallback:GF('americanexpress.com'), color:'2E77BC', initials:'AMEX', sector:'Finance',    founded:'Buffalo, New York, USA', year:1850, story:'American Express was founded on March 18, 1850 in Buffalo, New York as an express mail business by Henry Wells, William Fargo, and John Butterfield. It later created the traveller\'s cheque in 1891 and launched the first credit card in 1958. Amex became synonymous with elite travel and entertainment, attracting wealthy cardholders with premium services and airport lounges. Its charge cards, most famously the Centurion Black Card, became status symbols. American Express has consistently ranked as one of the world\'s most valuable financial services brands.', rating:4.6, reviews:98000 },

  // RETAIL AND CONSUMER
  { id:39, name:'IKEA',           logo:SI('ikea','0058A3'),             fallback:GF('ikea.com'),            color:'0058A3', initials:'IKEA', sector:'Retail',      founded:'Älmhult, Sweden', year:1943, story:'IKEA was founded in 1943 by 17-year-old Ingvar Kamprad in Älmhult, Småland, Sweden. The name is an acronym of the founder\'s initials and his farm and village: Ingvar Kamprad Elmtaryd Agunnaryd. Kamprad grew up in a poor farming region and built his business philosophy around providing well-designed, functional products at prices most people could afford. The flat-pack furniture revolution, which customers assemble themselves, allowed huge reductions in shipping and storage costs. IKEA now operates over 450 stores in 62 countries and is the world\'s largest furniture retailer.', rating:4.4, reviews:167000 },
  { id:40, name:'Zara',           logo:SI('zara','000000'),             fallback:GF('zara.com'),            color:'000000', initials:'ZARA', sector:'Fashion',     founded:'A Coruña, Spain', year:1975, story:'Zara was founded in 1975 by Amancio Ortega and Rosalía Mera in A Coruña, Galicia, Spain. Ortega, who started working in fashion at age 13, built Zara around a revolutionary fast fashion model where new designs go from concept to store in as little as two weeks, compared to six months for traditional fashion retailers. Zara is the flagship brand of Inditex, the world\'s largest fashion retailer. Its model of constantly refreshed inventory encourages customers to visit stores frequently and buy immediately. Amancio Ortega is one of the richest people in the world.', rating:4.3, reviews:134000 },
  { id:41, name:'H&M',            logo:SI('hm','E50010'),               fallback:GF('hm.com'),              color:'E50010', initials:'H&M', sector:'Fashion',      founded:'Västerås, Sweden', year:1947, story:'H&M, Hennes and Mauritz, was founded in 1947 by Erling Persson in Västerås, Sweden, initially as a women\'s clothing store called Hennes meaning "Hers" in Swedish. The company acquired a hunting and fishing equipment store called Mauritz Widforss in 1968 and adopted the combined name. H&M pioneered the concept of affordable fashion at scale, opening stores across Europe before expanding globally. It was one of the first major retailers to collaborate with luxury designers including Karl Lagerfeld and Stella McCartney at accessible price points. H&M operates over 4,300 stores in 77 countries.', rating:4.2, reviews:123000 },
  { id:42, name:'Walmart',        logo:SI('walmart','0071CE'),          fallback:GF('walmart.com'),         color:'0071CE', initials:'WMT', sector:'Retail',       founded:'Rogers, Arkansas, USA', year:1962, story:'Walmart was founded on July 2, 1962 by Sam Walton in Rogers, Arkansas. Walton opened his first store with the principle that passing savings to customers through lower prices would build loyalty and volume. The strategy worked spectacularly. Walmart is the world\'s largest company by revenue with annual sales exceeding 600 billion dollars. It employs over 2.3 million people in the United States alone, making it the largest private employer on earth. The Walton family, who still owns over 50 percent of the company, is the wealthiest family in the world.', rating:4.2, reviews:145000 },
  { id:43, name:'Unilever',       logo:SI('unilever','004B87'),         fallback:GF('unilever.com'),        color:'004B87', initials:'UNI', sector:'Consumer Goods',founded:'London, United Kingdom', year:1929, story:'Unilever was formed in September 1929 through the merger of British soap maker Lever Brothers and Dutch margarine producer Margarine Unie. The combined company had complementary products and shared palm oil as a key raw material. Today Unilever owns over 400 brands including Dove, Knorr, Lipton, Ben & Jerry\'s, Axe, and Hellmann\'s. Its products reach 3.4 billion people every day across 190 countries. Unilever has been a leader in corporate sustainability commitments and was among the first major companies to link executive pay to social and environmental goals.', rating:4.3, reviews:112000 },
  { id:44, name:'Procter & Gamble',logo:SI('proctergamble','003DA5'),   fallback:GF('pg.com'),              color:'003DA5', initials:'P&G', sector:'Consumer Goods',founded:'Cincinnati, Ohio, USA', year:1837, story:'Procter and Gamble was founded on October 31, 1837 by brothers-in-law William Procter and James Gamble in Cincinnati, Ohio. Procter was a candle maker and Gamble was a soap maker. The company grew through the American Civil War supplying the Union Army and later pioneered modern advertising and brand management techniques. P&G brands include Tide, Pampers, Gillette, Oral-B, Pantene, and Olay. It is among the world\'s top advertisers, spending over ten billion dollars per year on marketing. P&G invented the concept of brand management in the 1930s, a system now used by virtually every consumer goods company.', rating:4.3, reviews:98000 },

  // AIRLINES AND TRAVEL
  { id:45, name:'Emirates',       logo:SI('emirates','D71921'),         fallback:GF('emirates.com'),        color:'D71921', initials:'EK',  sector:'Aviation',     founded:'Dubai, UAE', year:1985, story:'Emirates airline was founded in March 1985 with a capital of just 10 million dollars from the Dubai government and two leased aircraft. It grew to become the world\'s largest long-haul airline and a symbol of Dubai\'s transformation into a global hub city. Emirates operates the world\'s largest fleet of Airbus A380 superjumbo jets and Boeing 777 aircraft. The airline flies to over 150 destinations in 80 countries. It has redefined long-haul flying with its premium onboard experience including private suites on its A380s and has won hundreds of international aviation awards.', rating:4.8, reviews:112000 },
  { id:46, name:'Airbus',         logo:SI('airbus','00205B'),           fallback:GF('airbus.com'),          color:'00205B', initials:'ABus', sector:'Aviation',    founded:'Toulouse, France', year:1970, story:'Airbus was established in December 1970 as a European consortium in Toulouse, France, to challenge the American dominance of commercial aviation by Boeing and McDonnell Douglas. The founding partners were France, Germany, the United Kingdom, and Spain. The A300, launched in 1972, was the world\'s first twin-aisle twin-engine jet. The A380 double-deck superjumbo, first flown in 2005, is the largest passenger aircraft ever built. Airbus and Boeing share roughly equal market share in commercial aviation and between them supply virtually all large commercial aircraft worldwide.', rating:4.6, reviews:78000 },
  { id:47, name:'Booking.com',    logo:SI('bookingcom','003580'),       fallback:GF('booking.com'),         color:'003580', initials:'BKG', sector:'Travel',        founded:'Amsterdam, Netherlands', year:1996, story:'Booking.com was founded in 1996 by Geert-Jan Bruinsma as a small Amsterdam startup. It was acquired by Booking Holdings (then Priceline Group) in 2005 for 133 million dollars, which proved to be one of the greatest acquisitions in internet history. Booking.com grew to become the world\'s largest online travel agency with over 28 million reported accommodation listings including hotels, apartments, villas, and homes in 220 countries. Its simple interface, free cancellation policies, and extensive reviews revolutionised how people book travel and fundamentally disrupted the traditional travel agency industry.', rating:4.5, reviews:145000 },
  { id:48, name:'Airbnb',         logo:SI('airbnb','FF5A5F'),           fallback:GF('airbnb.com'),          color:'FF5A5F', initials:'ABNB', sector:'Travel',       founded:'San Francisco, California, USA', year:2008, story:'Airbnb was founded in August 2008 by Brian Chesky, Joe Gebbia, and Nathan Blecharczyk in San Francisco, California. The founders initially rented out air mattresses in their apartment to conference attendees who could not find hotel rooms, hence the original name Air Bed and Breakfast. The idea grew into a platform disrupting the hotel industry worldwide. Airbnb now lists over seven million properties in 220 countries. It went public in December 2020 in one of the largest IPOs of that year and its market value exceeded that of major hotel chains. It has fundamentally changed how people think about travel and accommodation.', rating:4.6, reviews:167000 },

  // MEDIA AND ENTERTAINMENT
  { id:49, name:'Disney',         logo:SI('disney','113CCF'),           fallback:GF('disney.com'),          color:'113CCF', initials:'DIS', sector:'Entertainment', founded:'Los Angeles, California, USA', year:1923, story:'The Walt Disney Company was founded on October 16, 1923 by brothers Walt and Roy Disney in Los Angeles, California, initially as a cartoon studio. Mickey Mouse debuted in 1928 in Steamboat Willie, one of the first synchronised sound cartoons. Disney pioneered the animated feature film with Snow White and the Seven Dwarfs in 1937. It expanded into theme parks with Disneyland in 1955 and built one of the world\'s great entertainment empires through acquisitions of Pixar, Marvel, Lucasfilm, and 21st Century Fox. The Disney brand represents childhood wonder to billions of people globally.', rating:4.7, reviews:178000 },
  { id:50, name:'YouTube',        logo:SI('youtube','FF0000'),          fallback:GF('youtube.com'),         color:'FF0000', initials:'YT',  sector:'Entertainment', founded:'San Bruno, California, USA', year:2005, story:'YouTube was founded in February 2005 by three former PayPal employees, Chad Hurley, Steve Chen, and Jawed Karim, in San Bruno, California. The first video, uploaded by Jawed Karim on April 23, 2005, was titled "Me at the zoo." Google acquired YouTube for 1.65 billion dollars in October 2006, which seemed enormous at the time but proved to be an extraordinary bargain. YouTube now has over two billion logged-in users per month and over one billion hours of video are watched on the platform every single day. It has created an entirely new category of celebrity, the YouTuber, and transformed how media is produced and consumed.', rating:4.6, reviews:198000 },
  { id:51, name:'Instagram',      logo:SI('instagram','E1306C'),        fallback:GF('instagram.com'),       color:'E1306C', initials:'IG',  sector:'Social Media',  founded:'San Francisco, California, USA', year:2010, story:'Instagram was founded in October 2010 by Kevin Systrom and Mike Krieger in San Francisco, California. The app started as Burbn, a check-in app, before pivoting to photo sharing. It grew to one million users in just two months. Facebook acquired Instagram for approximately one billion dollars in April 2012, which proved to be one of the most visionary acquisitions in technology history. Instagram now has over two billion monthly active users and transformed photography, media, celebrity, marketing, and even the restaurant industry with its emphasis on visual aesthetics. It created the concept of the influencer as a professional category.', rating:4.5, reviews:187000 },
  { id:52, name:'TikTok',         logo:SI('tiktok','010101'),           fallback:GF('tiktok.com'),          color:'010101', initials:'TTK', sector:'Social Media',  founded:'Beijing, China', year:2016, story:'TikTok was launched internationally in September 2017 by ByteDance, a Chinese technology company founded by Zhang Yiming in Beijing in 2012. The app was the product of merging Musical.ly, an app ByteDance had acquired, with its own short video platform Douyin. TikTok\'s sophisticated recommendation algorithm proved revolutionary at keeping users engaged with a stream of short videos. It reached one billion monthly active users faster than any platform in history. TikTok fundamentally changed music, entertainment, marketing, and culture and inspired short-video formats across every competing platform including Instagram Reels and YouTube Shorts.', rating:4.3, reviews:167000 },
  { id:53, name:'Twitter/X',      logo:SI('x','000000'),               fallback:GF('x.com'),               color:'000000', initials:'X',   sector:'Social Media',  founded:'San Francisco, California, USA', year:2006, story:'Twitter was founded in March 2006 by Jack Dorsey, Noah Glass, Biz Stone, and Evan Williams in San Francisco, California. The 140-character message format was inspired by SMS text messages. Twitter became the essential platform for real-time news, political discourse, and celebrity communication. US presidents, world leaders, and pop stars used it as their primary public communication channel. Elon Musk acquired Twitter for 44 billion dollars in October 2022 and rebranded it to X, causing significant controversy. Despite turbulence, X remains a major platform for public discourse and breaking news globally.', rating:3.9, reviews:145000 },
  { id:54, name:'LinkedIn',       logo:SI('linkedin','0A66C2'),         fallback:GF('linkedin.com'),        color:'0A66C2', initials:'LI',  sector:'Social Media',  founded:'Mountain View, California, USA', year:2002, story:'LinkedIn was founded in December 2002 by Reid Hoffman and co-founders in Mountain View, California and launched in May 2003. It was conceived as a professional social network at a time when social networking was primarily personal. LinkedIn grew to become the essential platform for professional networking, job searching, recruitment, and B2B marketing. Microsoft acquired LinkedIn for 26.2 billion dollars in June 2016, its largest acquisition at the time. LinkedIn now has over 950 million members in more than 200 countries and territories and has transformed how people manage their careers and professional relationships.', rating:4.3, reviews:123000 },

  // HEALTHCARE AND PHARMA
  { id:55, name:'Johnson & Johnson',logo:SI('johnson','CC0000'),       fallback:GF('jnj.com'),             color:'CC0000', initials:'J&J', sector:'Healthcare',    founded:'New Brunswick, New Jersey, USA', year:1886, story:'Johnson and Johnson was founded in 1886 by brothers Robert Wood Johnson I, James Wood Johnson, and Edward Mead Johnson in New Brunswick, New Jersey. The company initially produced ready-to-use surgical dressings based on ideas from surgeon Joseph Lister about antiseptic medicine. It became famous for consumer products including Band-Aid bandages, Johnson\'s Baby Powder, and Tylenol pain reliever. Johnson and Johnson is one of the world\'s most diversified healthcare companies with products in consumer health, medical devices, and pharmaceuticals. During the COVID-19 pandemic it produced one of the major vaccines.', rating:4.4, reviews:98000 },
  { id:56, name:'Pfizer',          logo:SI('pfizer','0093D0'),          fallback:GF('pfizer.com'),          color:'0093D0', initials:'PFE', sector:'Pharmaceuticals',founded:'New York, USA', year:1849, story:'Pfizer was founded in 1849 by cousins Charles Pfizer and Charles Erhart in Brooklyn, New York, initially producing citric acid and other chemicals. The company\'s breakthrough came during World War II when it produced mass quantities of penicillin for the Allied forces. Pfizer became the world\'s largest pharmaceutical company through major acquisitions including Warner-Lambert, Pharmacia, and Wyeth. The Pfizer-BioNTech COVID-19 vaccine, developed in record time in 2020, was the first mRNA vaccine approved for emergency use and saved millions of lives during the pandemic.', rating:4.5, reviews:87000 },

  // SPORTS
  { id:57, name:'FIFA',            logo:SI('fifa','326295'),             fallback:GF('fifa.com'),            color:'326295', initials:'FIFA', sector:'Sports',      founded:'Paris, France', year:1904, story:'FIFA, the Fédération Internationale de Football Association, was founded on May 21, 1904 in Paris, France by representatives of football associations from Belgium, Denmark, France, the Netherlands, Spain, Sweden, and Switzerland. The organisation governs international association football and organises the FIFA World Cup, the most watched sporting event on earth with over five billion people watching the 2022 Qatar tournament. Football is the world\'s most popular sport played by 265 million players in 211 member associations worldwide.', rating:3.8, reviews:234000 },
  { id:58, name:'NBA',             logo:SI('nba','C9082A'),              fallback:GF('nba.com'),             color:'C9082A', initials:'NBA', sector:'Sports',       founded:'New York, USA', year:1946, story:'The National Basketball Association was founded on June 6, 1946 in New York City as the Basketball Association of America. It merged with the National Basketball League in 1949 to form the NBA. The league grew enormously in global popularity in the 1980s through the rivalry between Magic Johnson and Larry Bird and the emergence of Michael Jordan. Today the NBA has 30 teams and is the highest-paid professional sports league in the world by average salary. Through players like LeBron James and Stephen Curry, the NBA has become a truly global entertainment brand.', rating:4.5, reviews:178000 },
  { id:59, name:'Formula 1',       logo:SI('f1','E10600'),               fallback:GF('formula1.com'),        color:'E10600', initials:'F1',  sector:'Sports',       founded:'Paris, France', year:1950, story:'Formula 1 is the highest class of international single-seater auto racing, with its first World Championship season held in 1950. The sport is governed by the Fédération Internationale de l\'Automobile based in Paris. Formula 1 visits circuits across five continents and attracts hundreds of millions of television viewers worldwide. The sport underwent a transformation in global popularity following the Netflix documentary series Drive to Survive which introduced F1 to a massive new audience in North America. Lewis Hamilton has won seven World Championship titles, equalling Michael Schumacher\'s record.', rating:4.7, reviews:167000 },
  { id:60, name:'Adidas Originals',logo:SI('adidas','000000'),          fallback:GF('adidas.com'),          color:'000000', initials:'OGN', sector:'Sports',       founded:'Herzogenaurach, Germany', year:1972, story:'Adidas Originals began as the sportswear division of Adidas before becoming a full lifestyle brand in its own right. The Trefoil logo, introduced in 1972, was designated for the heritage and lifestyle range. Classic silhouettes like the Stan Smith tennis shoe, Superstar basketball shoe, and Samba football trainer became fashion icons decades after their original sporting use. Adidas Originals pioneered high fashion collaborations with designers including Yohji Yamamoto, Stella McCartney, and Kanye West through the Yeezy partnership, making streetwear culturally significant globally.', rating:4.5, reviews:134000 },

  // ENERGY AND INDUSTRY
  { id:61, name:'Shell',           logo:SI('shell','FBCF09'),            fallback:GF('shell.com'),           color:'FBCF09', initials:'SHL', sector:'Energy',       founded:'London, United Kingdom', year:1907, story:'Royal Dutch Shell was formed in February 1907 through the merger of Royal Dutch Petroleum and the British Shell Transport and Trading Company. The name Shell came from the original company started by Marcus Samuel who sold shells and then kerosene. Shell became one of the world\'s largest oil and gas companies and pioneered liquefied natural gas technology. The scallop shell logo is one of the most recognisable brand marks in the world. Shell has been investing in renewable energy and aims to become a net-zero emissions energy business by 2050.', rating:4.0, reviews:89000 },
  { id:62, name:'BP',              logo:SI('bp','009900'),               fallback:GF('bp.com'),              color:'009900', initials:'BP',  sector:'Energy',       founded:'London, United Kingdom', year:1909, story:'BP, formerly British Petroleum, was founded as the Anglo-Persian Oil Company in 1909 after oil was discovered in Persia, modern-day Iran. The company became one of the world\'s largest oil and gas producers. BP adopted its current logo, the Helios sunburst in green and yellow representing all forms of energy, in 2001 alongside the tagline Beyond Petroleum to emphasise its ambitions in renewable energy. The Deepwater Horizon oil spill in 2010 in the Gulf of Mexico was the largest accidental marine oil spill in history and cost BP over 65 billion dollars in cleanup and legal costs.', rating:3.9, reviews:76000 },

  // TECH ADDITIONS
  { id:63, name:'Uber',            logo:SI('uber','000000'),             fallback:GF('uber.com'),            color:'000000', initials:'UBER', sector:'Technology',  founded:'San Francisco, California, USA', year:2009, story:'Uber was founded in March 2009 by Travis Kalanick and Garrett Camp in San Francisco, California. The idea came to Camp after he spent 800 dollars on a private driver on New Year\'s Eve and wanted to reduce the cost. Uber launched its app in San Francisco in 2011 and rapidly expanded globally, disrupting the taxi industry in hundreds of cities. Uber is now present in over 70 countries and has expanded into food delivery with Uber Eats, freight logistics, and autonomous vehicle research. It went public in May 2019 and remains one of the defining companies of the gig economy era.', rating:4.3, reviews:167000 },
  { id:64, name:'Salesforce',      logo:SI('salesforce','00A1E0'),       fallback:GF('salesforce.com'),      color:'00A1E0', initials:'CRM', sector:'Technology',   founded:'San Francisco, California, USA', year:1999, story:'Salesforce was founded in February 1999 by Marc Benioff, Parker Harris, Dave Moellenhoff, and Frank Dominguez in a San Francisco apartment. Benioff had left Oracle to create the first cloud-based customer relationship management software. Salesforce pioneered the software-as-a-service model that transformed the entire enterprise software industry. Its famous "No Software" campaign challenged the traditional packaged software model. Salesforce has made over 60 acquisitions including MuleSoft, Tableau, and Slack, building one of the world\'s largest enterprise software ecosystems.', rating:4.4, reviews:78000 },
  { id:65, name:'Zoom',            logo:SI('zoom','2D8CFF'),             fallback:GF('zoom.us'),             color:'2D8CFF', initials:'ZM',  sector:'Technology',   founded:'San Jose, California, USA', year:2011, story:'Zoom Video Communications was founded in April 2011 by Eric Yuan in San Jose, California. Yuan, a former Cisco WebEx engineer, founded Zoom after becoming frustrated with the poor quality of existing video conferencing tools. The company remained relatively unknown until the COVID-19 pandemic of 2020, when lockdowns made video calling essential for work, school, and socialising worldwide. Zoom\'s name became a verb, with people saying "let\'s Zoom" as naturally as they say "let\'s Google." Its daily meeting participants grew from ten million in December 2019 to 300 million in April 2020.', rating:4.3, reviews:123000 },
  { id:66, name:'Slack',           logo:SI('slack','4A154B'),            fallback:GF('slack.com'),           color:'4A154B', initials:'SLK', sector:'Technology',   founded:'Vancouver, Canada', year:2013, story:'Slack was founded in August 2013 by Stewart Butterfield, Eric Costello, Cal Henderson, and Serguei Mourachov in Vancouver, Canada. It grew from an internal communication tool built for Butterfield\'s gaming company Glitch. Slack transformed workplace communication by replacing email for many team interactions with its channel-based messaging system. It became the fastest enterprise software company to reach a billion-dollar valuation. Salesforce acquired Slack for 27.7 billion dollars in 2021. Slack is now used by 12 million daily active users worldwide and has influenced how every tech company designs team collaboration software.', rating:4.4, reviews:87000 },
  { id:67, name:'Airtel Africa',   logo:SI('airtel','E40000'),           fallback:GF('airtel.africa'),       color:'E40000', initials:'AAF', sector:'Telecom',       founded:'London, United Kingdom', year:2010, story:'Airtel Africa is a leading telecommunications company operating in 14 countries across Sub-Saharan Africa with a customer base of over 140 million people. Listed on the London Stock Exchange and the Nigerian Stock Exchange, it provides voice, data, and mobile money services. Airtel Money has become one of the most significant mobile financial services platforms in Africa, processing billions of transactions and providing banking services to millions of previously unbanked Africans. The company has invested significantly in 4G network expansion across its markets.', rating:4.2, reviews:78000 },
  { id:68, name:'MTN Group',       logo:SI('mtn','FFCB00'),             fallback:GF('mtn.com'),             color:'FFCB00', initials:'MTN', sector:'Telecom',       founded:'Johannesburg, South Africa', year:1994, story:'MTN Group was founded in October 1994 in Johannesburg, South Africa, as a mobile network operator. It grew rapidly across Africa and the Middle East and is now the largest mobile network operator in Africa with over 280 million subscribers across 19 countries. MTN launched mobile money services in the early 2010s and has provided financial inclusion to millions of Africans without traditional bank accounts. The company is listed on the Johannesburg Stock Exchange and is a symbol of African corporate success on the global stage.', rating:4.3, reviews:98000 },
  { id:69, name:'Dangote Group',   logo:SI('dangote','E31B23'),         fallback:GF('dangote.com'),         color:'E31B23', initials:'DNG', sector:'Conglomerate',  founded:'Lagos, Nigeria', year:1981, story:'Dangote Group was founded in 1981 by Aliko Dangote in Lagos, Nigeria, initially as a trading company. Dangote is Africa\'s richest person with a net worth exceeding 13 billion dollars. The group has interests in cement manufacturing, sugar, flour milling, salt, and packaging across sub-Saharan Africa. Dangote Cement is the largest cement producer in sub-Saharan Africa with plants in 10 African countries. The Dangote Refinery in Lagos, completed in 2023, is the world\'s largest single-train petroleum refinery with a capacity of 650,000 barrels per day, transforming Nigeria\'s energy landscape.', rating:4.4, reviews:67000 },
  { id:70, name:'Safaricom',       logo:SI('safaricom','00A550'),        fallback:GF('safaricom.co.ke'),     color:'00A550', initials:'SCM', sector:'Telecom',       founded:'Nairobi, Kenya', year:1997, story:'Safaricom is Kenya\'s largest telecommunications company and the most profitable company in East and Central Africa. Founded in 1997 as a subsidiary of Telkom Kenya, Safaricom launched M-Pesa mobile money in 2007, revolutionising financial inclusion across Africa. M-Pesa now processes transactions worth more than Kenya\'s GDP annually. The company serves over 47 million subscribers and has expanded M-Pesa to Ethiopia. Safaricom\'s green branding is among the most recognised in Africa and the company is a model for how telecommunications can drive broader economic development.', rating:4.9, reviews:124000 },

  // FOOD GIANTS
  { id:71, name:'KFC',             logo:SI('kfc','F40027'),              fallback:GF('kfc.com'),             color:'F40027', initials:'KFC', sector:'Food',         founded:'Corbin, Kentucky, USA', year:1930, story:'KFC was founded by Harland Sanders in 1930 in Corbin, Kentucky, where he served fried chicken from his roadside restaurant. Sanders developed his secret blend of 11 herbs and spices during this time. He began franchising in 1952 at age 62 after the new interstate highway bypassed his restaurant. PepsiCo purchased KFC in 1986 as part of Yum! Brands. KFC now operates over 27,000 restaurants in more than 145 countries with China being its largest market. The image of Colonel Sanders in his white suit and string tie is one of the world\'s most recognisable corporate mascots.', rating:4.3, reviews:167000 },
  { id:72, name:'Pizza Hut',       logo:SI('pizzahut','EE3124'),         fallback:GF('pizzahut.com'),        color:'EE3124', initials:'PHT', sector:'Food',         founded:'Wichita, Kansas, USA', year:1958, story:'Pizza Hut was founded in June 1958 by brothers Dan and Frank Carney in Wichita, Kansas, with a loan of 600 dollars from their mother. The name came from the small building that could only fit a few letters on the sign. Pizza Hut was acquired by PepsiCo in 1977 and became part of Yum! Brands in 1997. It pioneered home pizza delivery and the concept of the pizza restaurant as a family dining destination. Pizza Hut now operates over 18,000 restaurants in more than 100 countries and was the first restaurant chain to make an online transaction and to deliver pizza in space.', rating:4.2, reviews:134000 },
  { id:73, name:'Subway',          logo:SI('subway','008C15'),           fallback:GF('subway.com'),          color:'008C15', initials:'SUB', sector:'Food',         founded:'Bridgeport, Connecticut, USA', year:1965, story:'Subway was founded in August 1965 by Fred DeLuca and family friend Peter Buck in Bridgeport, Connecticut. DeLuca was 17 years old and needed money for college. Buck lent him 1,000 dollars to open a submarine sandwich restaurant. The chain grew through franchising and at its peak became the world\'s largest restaurant chain by number of locations with over 45,000 outlets in 100 countries. The Subway brand is known for customisable sandwiches with fresh ingredients and positioned itself as a healthy fast food alternative. It pioneered the "eat fresh" positioning in the fast food industry.', rating:4.1, reviews:145000 },
  { id:74, name:'Burger King',     logo:SI('burgerking','F5003D'),       fallback:GF('burgerking.com'),      color:'F5003D', initials:'BK',  sector:'Food',         founded:'Jacksonville, Florida, USA', year:1953, story:'Burger King was founded in 1953 as Insta-Burger King in Jacksonville, Florida by Keith Cramer and his stepfather Matthew Burns. After the company fell into bankruptcy, Miami franchisees James McLamore and David Edgerton purchased it in 1954 and renamed it Burger King. The Whopper, introduced in 1957, became the signature product. Burger King is famous for its "Have it Your Way" approach allowing customers to customise orders. It operates over 18,700 restaurants in 100 countries and territories and has engaged in a decades-long fast food rivalry with McDonald\'s.', rating:4.2, reviews:156000 },

  // LUXURY CARS
  { id:75, name:'Lamborghini',     logo:SI('lamborghini','E1A024'),      fallback:GF('lamborghini.com'),     color:'E1A024', initials:'LAMBO', sector:'Automotive', founded:'Sant\'Agata Bolognese, Italy', year:1963, story:'Automobili Lamborghini was founded in May 1963 by Ferruccio Lamborghini in Sant\'Agata Bolognese, Italy. Lamborghini had made his fortune manufacturing tractors and was a Ferrari owner who complained to Enzo Ferrari about the clutch in his car. Ferrari reportedly dismissed him, saying a tractor maker should not tell a sports car maker how to build cars. Lamborghini proceeded to build his own supercar. The resulting rivalry produced some of the world\'s most dramatic and beautiful automobiles. The Miura of 1966 is considered the world\'s first supercar. Lamborghini is now owned by Volkswagen Group\'s Audi division.', rating:4.9, reviews:76000 },
  { id:76, name:'Rolls-Royce',     logo:SI('rollsroyce','A0906B'),      fallback:GF('rolls-royce.com'),     color:'A0906B', initials:'RR',  sector:'Automotive',   founded:'Manchester, United Kingdom', year:1906, story:'Rolls-Royce was founded on May 4, 1904 in Manchester by Charles Rolls and Henry Royce. Rolls was a car dealer and early aviator. Royce was a self-educated electrical and mechanical engineer who had built his own car dissatisfied with existing models. Their partnership produced what Rolls called the best car in the world. The Spirit of Ecstasy mascot was introduced in 1911. Rolls-Royce became the preferred choice of royalty, heads of state, and billionaires worldwide. The automotive brand was acquired by BMW in 1998 and today produces limited numbers of handcrafted vehicles in Goodwood, England.', rating:5.0, reviews:45000 },

  // CONSUMER ELECTRONICS
  { id:77, name:'Sony',            logo:SI('sony','000000'),             fallback:GF('sony.com'),            color:'000000', initials:'SNY', sector:'Technology',   founded:'Tokyo, Japan', year:1946, story:'Sony Corporation was founded on May 7, 1946 by Masaru Ibuka and Akio Morita in Tokyo, Japan, initially as Tokyo Tsushin Kogyo (Tokyo Telecommunications Engineering Corporation). The company pioneered the transistor radio in 1955, the Trinitron colour television in 1968, the Betamax videocassette in 1975, the Walkman portable music player in 1979, and the Compact Disc with Philips in 1982. Sony Pictures, Sony Music, and the PlayStation gaming console make it one of the world\'s most diversified entertainment and technology conglomerates. The PlayStation remains the world\'s best-selling home gaming console brand.', rating:4.6, reviews:145000 },
  { id:78, name:'LG Electronics',  logo:SI('lg','A50034'),               fallback:GF('lg.com'),              color:'A50034', initials:'LG',  sector:'Technology',   founded:'Seoul, South Korea', year:1958, story:'LG Electronics was founded in 1958 in Seoul, South Korea as Goldstar, a subsidiary of the LG Group (formerly Lucky-Goldstar). LG made South Korea\'s first radio in 1959 and its first television in 1966. The company adopted the LG name and the friendly face logo in 1995. LG became known for innovation in televisions, washing machines, refrigerators, and mobile phones. The company\'s OLED television technology, which produces the deepest blacks and most vibrant colours of any screen type, is widely considered the gold standard for home cinema display quality.', rating:4.4, reviews:112000 },

  // BANKING
  { id:79, name:'HSBC',            logo:SI('hsbc','DB0011'),             fallback:GF('hsbc.com'),            color:'DB0011', initials:'HSBC', sector:'Finance',     founded:'Hong Kong', year:1865, story:'HSBC, the Hongkong and Shanghai Banking Corporation, was founded in March 1865 in Hong Kong to finance the growing trade between China and Europe. The bank opened its doors in Shanghai a month later. The distinctive red and white hexagon logo represents the original house flag of the shipping and trading company that founded it. HSBC grew to become one of the world\'s largest banks with total assets exceeding 3 trillion dollars, operating in 63 countries. It relocated its headquarters to London in 1993 and is today one of Europe\'s largest financial institutions.', rating:4.2, reviews:98000 },
  { id:80, name:'Goldman Sachs',   logo:SI('goldmansachs','7399C6'),     fallback:GF('goldmansachs.com'),    color:'7399C6', initials:'GS',  sector:'Finance',      founded:'New York, USA', year:1869, story:'Goldman Sachs was founded in 1869 by Marcus Goldman in New York City as a commercial paper business. His son-in-law Samuel Sachs joined in 1882. The firm grew to become one of the world\'s leading investment banks and financial services companies. Goldman Sachs played a central role in major IPOs including those of Ford, Microsoft, and Google. The firm was heavily scrutinised following the 2008 financial crisis but remained profitable. Goldman Sachs alumni occupy senior positions in central banks, governments, and corporations worldwide, giving rise to the term "Government Sachs."', rating:4.3, reviews:76000 },

  // PHARMA AND BEAUTY
  { id:81, name:'L\'Oréal',        logo:SI('loreal','AA0000'),           fallback:GF('loreal.com'),          color:'AA0000', initials:'LOR', sector:'Beauty',       founded:'Clichy, France', year:1909, story:'L\'Oréal was founded in 1909 by chemist Eugène Schueller in Paris, France, who developed a hair dye formula and sold it to Parisian hairdressers. The company grew to become the world\'s largest cosmetics company with over 36 brands including Lancôme, Maybelline, Kiehl\'s, Garnier, NYX, and Giorgio Armani Beauty. L\'Oréal operates in 150 countries and its famous tagline "Because You\'re Worth It," introduced in 1973, is one of the most recognisable advertising slogans in history. The company invests heavily in research and development with over 6,000 scientists working in cosmetic innovation.', rating:4.5, reviews:112000 },
  { id:82, name:'Dove',            logo:SI('dove','FFFFFF'),             fallback:GF('dove.com'),            color:'005BAC', initials:'DOVE', sector:'Beauty',      founded:'Boston, Massachusetts, USA', year:1955, story:'Dove was created by Unilever in 1955 in the United States, initially as a soap bar with a moisturising formula developed for treating skin burns of soldiers in World War II. The distinctive white bar with a distinctive cream formulation was marketed as gentler than ordinary soap. In 2004 Dove launched its Real Beauty campaign featuring women of diverse body types and ages in advertising, which became one of the most celebrated and discussed marketing campaigns in history, fundamentally shifting beauty advertising standards worldwide. Dove is now a multi-billion-dollar brand sold in over 80 countries.', rating:4.5, reviews:98000 },

  // SPORT AND ENTERTAINMENT
  { id:83, name:'Red Cross',       logo:SI('redcross','ED1B24'),         fallback:GF('icrc.org'),            color:'ED1B24', initials:'ICRC', sector:'Humanitarian',founded:'Geneva, Switzerland', year:1863, story:'The International Red Cross was founded by Swiss businessman Henry Dunant in Geneva, Switzerland in 1863, inspired by the suffering he witnessed at the Battle of Solferino in 1859. Dunant proposed the creation of national volunteer societies to care for the wounded in wartime, and an international agreement to guarantee their protection. The Geneva Conventions, first adopted in 1864, established the legal framework for humanitarian treatment of combatants and civilians in war. The Red Cross and Red Crescent movement is now the world\'s largest humanitarian network, operating in every country and responding to conflicts and disasters globally.', rating:4.8, reviews:87000 },
  { id:84, name:'UNICEF',          logo:SI('unicef','00AEEF'),           fallback:GF('unicef.org'),          color:'00AEEF', initials:'UNICEF', sector:'Humanitarian',founded:'New York, USA', year:1946, story:'UNICEF, the United Nations International Children\'s Emergency Fund, was established on December 11, 1946 in New York to provide food, clothing, and healthcare to children in countries devastated by World War II. It became a permanent part of the United Nations system in 1953 and expanded its mandate to address long-term needs of children in developing countries. UNICEF operates in 190 countries and territories providing aid for healthcare, education, clean water, nutrition, and protection from violence. It is funded entirely by voluntary contributions from governments and private donors.', rating:4.8, reviews:87000 },

  // SPORT BRANDS
  { id:85, name:'Puma',            logo:SI('puma','000000'),             fallback:GF('puma.com'),            color:'000000', initials:'PUM', sector:'Fashion',      founded:'Herzogenaurach, Germany', year:1948, story:'Puma was founded on October 1, 1948 by Rudolf Dassler in Herzogenaurach, Germany, shortly after the bitter feud with his brother Adolf who founded Adidas. The two brothers had run a joint shoe company before their relationship broke down irreparably. Puma sponsored the legendary Pelé and Jamaican sprinter Usain Bolt, who made the brand famous with his laces gesture at the 2008 Olympics. Puma has positioned itself at the intersection of sport and fashion, collaborating with designers and celebrities. The Kering Group, which owns Gucci and Balenciaga, is the major shareholder.', rating:4.4, reviews:112000 },
  { id:86, name:'Under Armour',    logo:SI('underarmour','E31837'),      fallback:GF('underarmour.com'),     color:'E31837', initials:'UA',  sector:'Fashion',      founded:'Baltimore, Maryland, USA', year:1996, story:'Under Armour was founded in 1996 by Kevin Plank in Washington D.C., initially from his grandmother\'s basement. Plank was a former football player at the University of Maryland who was frustrated with the cotton t-shirts worn under football gear that became heavy with sweat. He developed a synthetic moisture-wicking compression shirt. Under Armour grew into a multi-billion-dollar global brand through endorsements from athletes including Stephen Curry, Dwayne Johnson, and Michael Phelps. The company challenges Nike and Adidas in performance sportswear globally.', rating:4.3, reviews:98000 },

  // LOGISTICS
  { id:87, name:'DHL',             logo:SI('dhl','D40511'),              fallback:GF('dhl.com'),             color:'D40511', initials:'DHL', sector:'Logistics',    founded:'San Francisco, California, USA', year:1969, story:'DHL was founded in 1969 by Adrian Dalsey, Larry Hillblom, and Robert Lynn in San Francisco, California. The name DHL is made from the first letters of the founders\' surnames. The company originally offered a door-to-door courier service between San Francisco and Honolulu, bypassing the slow customs process by sending documents ahead of cargo shipments. DHL was acquired by Deutsche Post in 2002. It is now the world\'s leading logistics company operating in over 220 countries and territories, delivering over 1.8 billion packages annually with over 600,000 employees worldwide.', rating:4.5, reviews:112000 },
  { id:88, name:'FedEx',           logo:SI('fedex','4D148C'),            fallback:GF('fedex.com'),           color:'4D148C', initials:'FDX', sector:'Logistics',    founded:'Memphis, Tennessee, USA', year:1971, story:'FedEx, Federal Express, was founded in 1971 by Frederick W. Smith in Memphis, Tennessee. Smith had outlined the concept of an overnight delivery service in a Yale University paper years earlier. He raised 91 million dollars in venture capital to build a hub-and-spoke air freight system. FedEx launched in April 1973 delivering to 25 cities. The company pioneered real-time package tracking and revolutionised global logistics. The FedEx logo, designed in 1994, contains a hidden arrow between the E and X which is often cited as an example of brilliant subliminal graphic design.', rating:4.5, reviews:98000 },

  // STREAMING AND MEDIA
  { id:89, name:'HBO',             logo:SI('hbo','000000'),              fallback:GF('hbo.com'),             color:'000000', initials:'HBO', sector:'Entertainment', founded:'New York, USA', year:1972, story:'Home Box Office, HBO, was launched on November 8, 1972 in Wilkes-Barre, Pennsylvania, as the first premium cable television network in the United States. It pioneered original programming and became famous for groundbreaking series including The Sopranos, The Wire, Game of Thrones, and Succession. HBO\'s slogan "It\'s Not TV, It\'s HBO" reflected its ambition to create cinematic-quality content. The network demonstrated that television could be a serious art form. Warner Bros. Discovery operates HBO Max as a streaming service combining the HBO brand with the broader studio library. Game of Thrones became the most-watched television series in history at its peak.', rating:4.7, reviews:134000 },
  { id:90, name:'Warner Bros.',    logo:SI('warnerbros','0060A9'),       fallback:GF('warnerbros.com'),      color:'0060A9', initials:'WB',  sector:'Entertainment', founded:'Burbank, California, USA', year:1923, story:'Warner Bros. was founded on April 4, 1923 by four brothers Harry, Albert, Sam, and Jack Warner in Burbank, California. The studio pioneered the "talkie" film era with The Jazz Singer in 1927. Warner Bros. created some of cinema\'s most enduring characters including Bugs Bunny, Batman, and Superman. Its DC Comics universe, the Harry Potter franchise, and The Lord of the Rings films are among the most successful film properties ever made. Warner Bros. merged with Discovery Inc. in 2022 to form Warner Bros. Discovery, one of the world\'s leading media and entertainment companies.', rating:4.5, reviews:112000 },

  // MORE GLOBAL BRANDS
  { id:91, name:'LEGO',            logo:SI('lego','E3000B'),             fallback:GF('lego.com'),            color:'E3000B', initials:'LEGO', sector:'Toys',        founded:'Billund, Denmark', year:1932, story:'LEGO was founded in 1932 by Ole Kirk Christiansen in Billund, Denmark. The name comes from the Danish words "leg godt" meaning "play well." Christiansen was a carpenter who began making wooden toys. The famous interlocking plastic brick was developed in 1949 and patented in its current form in 1958. LEGO became the world\'s most powerful toy brand and was named the Toy of the Century by Fortune magazine. The company famously nearly went bankrupt in 2004 before a dramatic turnaround. The LEGO Movie franchise and LEGO video games have extended the brand into entertainment. The Christiansen family remains the owners.', rating:4.8, reviews:156000 },
  { id:92, name:'Volkswagen',      logo:SI('volkswagen','151F6D'),       fallback:GF('vw.com'),              color:'151F6D', initials:'VW',  sector:'Automotive',   founded:'Wolfsburg, Germany', year:1937, story:'Volkswagen, meaning People\'s Car in German, was established in May 1937 in Wolfsburg, Germany by the German Labour Front under the Nazi regime, with Ferdinand Porsche designing the original Beetle. After World War II the company was taken over by the British military and then handed to the German government. The Beetle became one of the most beloved cars in history. The VW Golf, introduced in 1974, is among the best-selling cars ever made. The Volkswagen Group now includes Audi, Porsche, Lamborghini, Bentley, SEAT, Skoda, and Ducati, making it one of the world\'s largest automotive groups.', rating:4.4, reviews:134000 },
  { id:93, name:'Alibaba',         logo:SI('alibaba','FF6A00'),          fallback:GF('alibaba.com'),         color:'FF6A00', initials:'BABA', sector:'E-Commerce',  founded:'Hangzhou, China', year:1999, story:'Alibaba was founded on June 28, 1999 by Jack Ma and 17 co-founders in Jack Ma\'s apartment in Hangzhou, China. Ma was a former English teacher who had no coding experience and was rejected 10 times by Harvard Business School. Alibaba built China\'s dominant e-commerce ecosystem including Taobao, Tmall, and Alipay. The company\'s 2014 IPO on the New York Stock Exchange raised 25 billion dollars, the largest IPO in history at that time. Alibaba Cloud is one of the world\'s largest cloud computing providers. The company has faced significant regulatory pressure from the Chinese government since 2020.', rating:4.3, reviews:145000 },
  { id:94, name:'Huawei',          logo:SI('huawei','CF0A2C'),           fallback:GF('huawei.com'),          color:'CF0A2C', initials:'HWI', sector:'Technology',   founded:'Shenzhen, China', year:1987, story:'Huawei was founded in 1987 by Ren Zhengfei, a former engineer in the People\'s Liberation Army, in Shenzhen, China, with an initial capital of 21,000 Chinese yuan. The company grew from a reseller of telephone network equipment to become the world\'s largest manufacturer of telecommunications equipment and one of the three largest smartphone makers. Huawei is a leader in 5G network technology. The US government placed Huawei on its export blacklist in 2019 citing national security concerns, cutting it off from critical American technology and significantly impacting its smartphone business. It remains one of China\'s most globally recognised technology brands.', rating:4.2, reviews:112000 },
  { id:95, name:'Spotify',         logo:SI('spotify','1DB954'),          fallback:GF('spotify.com'),         color:'1DB954', initials:'SPOT', sector:'Entertainment',founded:'Stockholm, Sweden', year:2008, story:'Spotify\'s streaming service launched publicly in October 2008 in Sweden after two years of development. The platform changed the music industry from ownership to access, offering millions of songs for a monthly subscription fee. Spotify became the world\'s most-used music streaming service with over 600 million users in 180 countries. Its podcast strategy, including exclusive deals with Joe Rogan worth over 250 million dollars, expanded the platform beyond music. Spotify went public in April 2018 through a direct listing on the New York Stock Exchange, choosing not to raise new capital in an unusual IPO structure that became a model for other tech companies.', rating:4.7, reviews:134000 },
  { id:96, name:'Mastercard',      logo:SI('mastercard','EB001B'),       fallback:GF('mastercard.com'),      color:'EB001B', initials:'MCRD', sector:'Finance',     founded:'New York, USA', year:1966, story:'Mastercard\'s global network connects billions of cardholders to millions of merchants in over 210 countries and territories. Its indelible two-circle logo, with the red and orange spheres representing the connection between people and possibilities, is one of the most internationally recognised brand symbols. Mastercard has led industry innovation in contactless payment technology, biometric authentication, and cryptocurrency integration. Its Priceless campaign launched in 1997 with the tagline "There are some things money can\'t buy. For everything else there\'s Mastercard" became one of advertising history\'s most enduring campaigns.', rating:4.5, reviews:112000 },
];
